function page(
  title: string,
  active: StitchScreenId,
  body: string,
  onchainAvailable: boolean,
  chrome = true,
) {
  return String.raw`<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1, viewport-fit=cover" />
  <title>${title}</title>
  <style>
    :root {
      color-scheme: dark;
      --bg0: #05070C;
      --bg1: #0A0F17;
      --panel: rgba(255, 255, 255, 0.045);
      --panel-deep: rgba(13, 18, 28, 0.90);
      --line: rgba(148, 163, 184, 0.14);
      --line-strong: rgba(148, 163, 184, 0.22);
      --line-purple: rgba(153, 69, 255, 0.30);
      --line-cyan: rgba(0, 209, 255, 0.28);
      --line-emerald: rgba(20, 241, 149, 0.28);
      --text: #F8FAFC;
      --muted: #94A3B8;
      --soft: #64748B;
      --purple: #9945FF;
      --purple-deep: #7C3AED;
      --cyan: #00D1FF;
      --emerald: #14F195;
      --amber: #F59E0B;
      --danger: #FB7185;
      --violet: #C4B5FD;
      --prime: #C084FC;
      --cta-grad: linear-gradient(135deg, #9945FF 0%, #7C3AED 45%, #00D1FF 130%);
    }

    * { box-sizing: border-box; }

    html, body {
      margin: 0;
      width: 100%;
      max-width: 100%;
      min-height: 100%;
      background:
        radial-gradient(circle at 12% 0%, rgba(153, 69, 255, 0.14), transparent 30rem),
        radial-gradient(circle at 95% 30%, rgba(0, 209, 255, 0.07), transparent 26rem),
        radial-gradient(circle at 50% 100%, rgba(124, 58, 237, 0.08), transparent 30rem),
        linear-gradient(180deg, var(--bg1), var(--bg0));
      color: var(--text);
      font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      font-size: 16px;
      -webkit-font-smoothing: antialiased;
      overflow-x: hidden;
    }

    button, a { -webkit-tap-highlight-color: transparent; color: inherit; font: inherit; }
    button { cursor: pointer; }

    :focus-visible { outline: 2px solid var(--cyan); outline-offset: 2px; border-radius: 10px; }

    .app {
      width: 100%;
      max-width: 760px;
      min-height: 100dvh;
      margin: 0 auto;
      padding: 10px 16px calc(env(safe-area-inset-bottom) + 104px);
      overflow-x: hidden;
    }

    .app.standalone-app {
      max-width: 1200px;
      padding: 10px 10px calc(env(safe-area-inset-bottom) + 16px);
    }

    .topbar {
      position: sticky;
      top: 0;
      z-index: 10;
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 12px;
      min-height: 60px;
      margin: -10px -16px 12px;
      padding: 10px 16px;
      background: rgba(10, 15, 23, 0.88);
      border-bottom: 1px solid var(--line);
      backdrop-filter: blur(18px);
    }

    .brand { display: flex; align-items: center; gap: 10px; min-width: 0; }
    .brand img { width: 42px; height: auto; flex: 0 0 auto; filter: drop-shadow(0 0 10px rgba(20, 241, 149, 0.25)); }
    .brand-text { display: grid; gap: 1px; font-size: 19px; font-weight: 800; letter-spacing: -0.01em; line-height: 1; }
    .brand-text small { color: var(--soft); font-size: 10.5px; font-weight: 700; letter-spacing: 0.12em; text-transform: uppercase; }

    .top-actions { display: flex; align-items: center; gap: 8px; min-width: 0; }

    .pill, .ghost-button {
      min-height: 36px;
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 8px;
      padding: 0 12px;
      border-radius: 999px;
      border: 1px solid var(--line);
      background: var(--panel);
      color: var(--muted);
      font-size: 12px;
      font-weight: 700;
      text-decoration: none;
      white-space: nowrap;
    }

    .ghost-button { border-color: var(--line-purple); color: var(--violet); box-shadow: 0 0 18px rgba(153, 69, 255, 0.14); }

    .status-dot { width: 7px; height: 7px; border-radius: 50%; flex: 0 0 auto; }
    .dot-live { background: var(--emerald); box-shadow: 0 0 12px rgba(20, 241, 149, 0.55); }
    .dot-sync { background: var(--amber); box-shadow: 0 0 12px rgba(245, 158, 11, 0.5); }
    .pill-sync { color: #FBD38D; border-color: rgba(245, 158, 11, 0.30); background: rgba(245, 158, 11, 0.07); }

    .stack { display: grid; gap: 14px; }
    .compact-stack { display: grid; gap: 10px; }

    .eyebrow {
      color: var(--cyan);
      font-size: 11px;
      font-weight: 800;
      letter-spacing: 0.16em;
      text-transform: uppercase;
    }

    h1, h2, h3, p { margin: 0; }
    h1 { color: #fff; font-size: 29px; line-height: 1.12; font-weight: 850; letter-spacing: -0.02em; }
    h2 { color: #fff; font-size: 20px; line-height: 1.2; font-weight: 800; letter-spacing: -0.01em; }
    h3 { color: #fff; font-size: 16px; line-height: 1.25; font-weight: 750; }
    p { color: var(--muted); line-height: 1.5; font-size: 14.5px; overflow-wrap: anywhere; }

    .muted { color: var(--muted); }
    .soft { color: var(--soft); }
    .success { color: var(--emerald); }
    .warning { color: var(--amber); }
    .mono {
      font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace;
      font-variant-numeric: tabular-nums;
      overflow-wrap: anywhere;
      word-break: break-word;
    }

    .panel, .pool-card, .list-row, .hero-card, .badge {
      border: 1px solid var(--line);
      border-radius: 16px;
      background: var(--panel);
      backdrop-filter: blur(20px);
    }

    .panel { padding: 16px; }
    .panel.glow-purple { border-color: var(--line-purple); box-shadow: 0 0 28px rgba(153, 69, 255, 0.10); }
    .panel.glow-cyan { border-color: var(--line-cyan); box-shadow: 0 0 28px rgba(0, 209, 255, 0.08); }
    .panel.glow-amber { border-color: rgba(245, 158, 11, 0.26); background: rgba(245, 158, 11, 0.05); }

    .label {
      color: var(--soft);
      font-size: 11px;
      font-weight: 800;
      letter-spacing: 0.1em;
      text-transform: uppercase;
    }

    /* ---------- hero ---------- */

    .hero-card {
      position: relative;
      overflow: hidden;
      display: grid;
      gap: 14px;
      padding: 20px 16px 18px;
      border-color: var(--line-purple);
      background:
        radial-gradient(circle at 85% 0%, rgba(153, 69, 255, 0.16), transparent 22rem),
        radial-gradient(circle at 10% 100%, rgba(0, 209, 255, 0.10), transparent 20rem),
        var(--panel-deep);
      box-shadow: 0 0 36px rgba(124, 58, 237, 0.16);
    }

    .hero-art { display: block; width: min(64%, 300px); height: auto; margin: 0 auto; }
    .hero-art.small { width: min(46%, 210px); }

    .hero-copy { display: grid; gap: 10px; }

    .chip-row { display: flex; flex-wrap: wrap; gap: 8px; }

    .chip {
      display: inline-flex;
      align-items: center;
      gap: 6px;
      min-height: 30px;
      padding: 0 11px;
      border-radius: 999px;
      font-size: 12px;
      font-weight: 750;
      white-space: nowrap;
    }
    .chip-p { color: var(--violet); background: rgba(153, 69, 255, 0.10); border: 1px solid var(--line-purple); }
    .chip-c { color: var(--cyan); background: rgba(0, 209, 255, 0.08); border: 1px solid var(--line-cyan); }
    .chip-e { color: var(--emerald); background: rgba(20, 241, 149, 0.07); border: 1px solid var(--line-emerald); }
    .chip-a { color: #FBD38D; background: rgba(245, 158, 11, 0.08); border: 1px solid rgba(245, 158, 11, 0.28); }

    .cta-row { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }

    /* ---------- status pills / chips ---------- */

    .status-pill {
      display: inline-flex;
      align-items: center;
      gap: 6px;
      padding: 4px 10px;
      border-radius: 999px;
      font-size: 11px;
      font-weight: 800;
      letter-spacing: 0.08em;
      text-transform: uppercase;
      flex: 0 0 auto;
      white-space: nowrap;
    }
    .status-pill.amber { color: #FBD38D; background: rgba(245, 158, 11, 0.10); border: 1px solid rgba(245, 158, 11, 0.28); }
    .status-pill.emerald { color: var(--emerald); background: rgba(20, 241, 149, 0.08); border: 1px solid rgba(20, 241, 149, 0.26); }
    .status-pill.neutral { color: var(--muted); background: var(--panel); border: 1px solid var(--line); }

    .icon-chip {
      display: grid;
      place-items: center;
      width: 38px;
      height: 38px;
      border-radius: 12px;
      flex: 0 0 auto;
    }
    .icon-chip svg { width: 21px; height: 21px; }
    .chip-amberbox { color: var(--amber); background: rgba(245, 158, 11, 0.10); border: 1px solid rgba(245, 158, 11, 0.24); }
    .chip-emeraldbox { color: var(--emerald); background: rgba(20, 241, 149, 0.08); border: 1px solid rgba(20, 241, 149, 0.22); }
    .chip-purplebox { color: var(--violet); background: rgba(153, 69, 255, 0.12); border: 1px solid rgba(153, 69, 255, 0.26); }
    .chip-cyanbox { color: var(--cyan); background: rgba(0, 209, 255, 0.09); border: 1px solid rgba(0, 209, 255, 0.24); }

    /* ---------- rows / lists ---------- */

    .row { display: flex; align-items: center; justify-content: space-between; gap: 14px; min-width: 0; }
    .row > *, .list-row > * { min-width: 0; }
    .row-left { display: flex; align-items: center; gap: 12px; min-width: 0; }

    .kv { display: grid; gap: 9px; }
    .kv .row { padding: 9px 0; border-bottom: 1px solid rgba(148, 163, 184, 0.09); }
    .kv .row:last-child { border-bottom: 0; padding-bottom: 0; }
    .kv .row:first-child { padding-top: 0; }
    .kv strong { color: #fff; font-size: 14px; font-weight: 750; }

    .list { display: grid; gap: 10px; }
    .list-row { padding: 13px 14px; display: flex; align-items: center; justify-content: space-between; gap: 14px; }
    .list-row strong { flex: 0 0 auto; max-width: 38%; color: #fff; font-size: 14px; text-align: right; overflow-wrap: anywhere; }

    .section-header { display: flex; align-items: end; justify-content: space-between; gap: 12px; margin: 4px 0 -2px; }

    /* ---------- pool cards ---------- */

    .pool-grid { display: grid; gap: 12px; }

    .pool-card {
      position: relative;
      overflow: hidden;
      padding: 15px;
      display: grid;
      gap: 13px;
      background:
        radial-gradient(circle at 90% 0%, var(--accent-soft), transparent 16rem),
        var(--panel-deep);
      border-color: var(--accent-line);
      box-shadow: 0 0 26px var(--accent-glow);
    }

    .tone-cyan { --accent: var(--cyan); --accent-line: rgba(0, 209, 255, 0.26); --accent-soft: rgba(0, 209, 255, 0.08); --accent-glow: rgba(0, 209, 255, 0.08); }
    .tone-purple { --accent: var(--purple); --accent-line: rgba(153, 69, 255, 0.30); --accent-soft: rgba(153, 69, 255, 0.10); --accent-glow: rgba(153, 69, 255, 0.10); }
    .tone-violet { --accent: var(--purple-deep); --accent-line: rgba(124, 58, 237, 0.32); --accent-soft: rgba(124, 58, 237, 0.10); --accent-glow: rgba(124, 58, 237, 0.10); }
    .tone-prime { --accent: var(--prime); --accent-line: rgba(192, 132, 252, 0.30); --accent-soft: rgba(192, 132, 252, 0.10); --accent-glow: rgba(192, 132, 252, 0.10); }

    .pool-chip {
      display: inline-flex;
      align-items: center;
      gap: 6px;
      padding: 4px 10px;
      border-radius: 999px;
      font-size: 11px;
      font-weight: 800;
      letter-spacing: 0.08em;
      text-transform: uppercase;
      color: var(--accent);
      background: var(--accent-soft);
      border: 1px solid var(--accent-line);
      flex: 0 0 auto;
    }

    .pool-marker { color: var(--accent); background: var(--accent-soft); border: 1px solid var(--accent-line); }
    .pool-marker svg { width: 18px; height: 18px; }

    .entry-big { display: flex; align-items: baseline; gap: 6px; }
    .entry-big strong { color: var(--accent); font-size: 30px; font-weight: 850; letter-spacing: -0.02em; line-height: 1; }
    .entry-big span { color: var(--muted); font-size: 13px; font-weight: 800; letter-spacing: 0.06em; }

    .pool-facts { display: grid; grid-template-columns: repeat(3, minmax(0, 1fr)); gap: 8px; }

    .fact {
      min-height: 58px;
      padding: 9px 10px;
      border-radius: 10px;
      background: rgba(255, 255, 255, 0.035);
      border: 1px solid rgba(148, 163, 184, 0.10);
    }
    .fact .label { display: block; margin-bottom: 5px; font-size: 10px; }
    .fact strong { display: block; color: #fff; font-size: 12.5px; line-height: 1.2; overflow-wrap: anywhere; }

    .pool-note { display: flex; align-items: center; justify-content: space-between; gap: 12px; }

    /* ---------- buttons ---------- */

    .primary-button, .secondary-button, .nav-item { border: 0; text-decoration: none; transition: opacity 160ms ease, transform 160ms ease; }

    .primary-button, .secondary-button {
      min-height: 48px;
      border-radius: 13px;
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 8px;
      padding: 0 16px;
      font-size: 15px;
      font-weight: 800;
      white-space: nowrap;
    }

    .primary-button {
      color: #fff;
      background: var(--cta-grad);
      box-shadow: 0 10px 30px rgba(124, 58, 237, 0.35), 0 0 20px rgba(0, 209, 255, 0.12);
    }

    .secondary-button {
      color: var(--text);
      background: var(--panel);
      border: 1px solid var(--line-strong);
    }
    .secondary-button.disabled {
      opacity: 0.56;
      color: var(--soft);
    }
    .secondary-button svg { width: 16px; height: 16px; color: var(--soft); }

    .primary-button:active, .secondary-button:active, .nav-item:active { transform: scale(0.98); opacity: 0.8; }

    /* ---------- winner share card ---------- */

    .winner-shell {
      display: grid;
      gap: 14px;
      padding: 2px 0 8px;
    }

    .winner-card {
      position: relative;
      width: 100%;
      max-width: 1200px;
      aspect-ratio: 1200 / 630;
      display: grid;
      grid-template-columns: 1.05fr 0.95fr;
      gap: clamp(12px, 3vw, 28px);
      overflow: hidden;
      padding: clamp(18px, 5vw, 54px);
      border: 1px solid rgba(20, 241, 149, 0.32);
      border-radius: 16px;
      background:
        radial-gradient(circle at 16% 18%, rgba(20, 241, 149, 0.28), transparent 24%),
        radial-gradient(circle at 88% 16%, rgba(153, 69, 255, 0.30), transparent 28%),
        radial-gradient(circle at 74% 86%, rgba(0, 209, 255, 0.20), transparent 32%),
        linear-gradient(145deg, #071018 0%, #120D23 52%, #06131B 100%);
      box-shadow: 0 0 38px rgba(20, 241, 149, 0.13), 0 0 46px rgba(153, 69, 255, 0.16);
      isolation: isolate;
    }

    .winner-card::before {
      content: "";
      position: absolute;
      inset: 0;
      z-index: -1;
      background:
        linear-gradient(90deg, rgba(255,255,255,0.06) 1px, transparent 1px),
        linear-gradient(0deg, rgba(255,255,255,0.04) 1px, transparent 1px);
      background-size: 38px 38px;
      opacity: 0.26;
      mask-image: radial-gradient(circle at 45% 45%, black, transparent 76%);
    }

    .winner-brand {
      display: grid;
      align-content: space-between;
      min-width: 0;
    }

    .winner-logo-row {
      display: flex;
      align-items: center;
      gap: clamp(9px, 2.3vw, 18px);
      min-width: 0;
    }

    .winner-logo {
      width: clamp(54px, 14vw, 142px);
      height: auto;
      filter: drop-shadow(0 0 16px rgba(20, 241, 149, 0.32));
    }

    .winner-wordmark {
      display: grid;
      gap: 3px;
      min-width: 0;
    }

    .winner-wordmark strong {
      color: #fff;
      font-size: clamp(22px, 6vw, 64px);
      font-weight: 900;
      line-height: 0.96;
    }

    .winner-wordmark span,
    .winner-kicker,
    .winner-label {
      color: rgba(203, 213, 225, 0.72);
      font-size: clamp(9px, 2vw, 18px);
      font-weight: 800;
      letter-spacing: 0.13em;
      text-transform: uppercase;
    }

    .winner-title {
      display: grid;
      gap: clamp(6px, 1.8vw, 14px);
      margin-top: auto;
    }

    .winner-title h1 {
      font-size: clamp(24px, 9vw, 92px);
      line-height: 0.9;
      letter-spacing: 0;
      text-transform: uppercase;
      text-shadow: 0 0 30px rgba(153, 69, 255, 0.42);
    }

    .winner-title p {
      max-width: 34em;
      color: rgba(226, 232, 240, 0.78);
      font-size: clamp(11px, 2.6vw, 24px);
      line-height: 1.28;
    }

    .winner-details {
      display: grid;
      align-content: end;
      gap: clamp(8px, 2vw, 16px);
      min-width: 0;
    }

    .winner-amount {
      display: grid;
      gap: 5px;
      padding: clamp(12px, 3vw, 26px);
      border: 1px solid rgba(20, 241, 149, 0.28);
      border-radius: 14px;
      background: rgba(3, 9, 14, 0.44);
    }

    .winner-amount strong {
      color: #14F195;
      font-size: clamp(32px, 10vw, 102px);
      font-weight: 950;
      line-height: 0.92;
      letter-spacing: 0;
      text-shadow: 0 0 28px rgba(20, 241, 149, 0.32);
    }

    .winner-grid {
      display: grid;
      grid-template-columns: repeat(2, minmax(0, 1fr));
      gap: clamp(7px, 1.7vw, 12px);
    }

    .winner-fact {
      min-width: 0;
      padding: clamp(10px, 2.4vw, 18px);
      border: 1px solid rgba(148, 163, 184, 0.18);
      border-radius: 12px;
      background: rgba(255, 255, 255, 0.055);
    }

    .winner-fact strong {
      display: block;
      margin-top: 4px;
      color: #fff;
      font-size: clamp(12px, 3.2vw, 24px);
      line-height: 1.08;
      overflow-wrap: anywhere;
    }

    .share-panel {
      display: grid;
      gap: 10px;
      padding: 0 2px;
    }

    .share-title {
      color: var(--soft);
      font-size: 11px;
      font-weight: 900;
      letter-spacing: 0.18em;
      text-align: center;
      text-transform: uppercase;
    }

    .share-actions {
      display: grid;
      grid-template-columns: repeat(4, minmax(0, 1fr));
      gap: 8px;
    }

    .share-button {
      min-height: 48px;
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 8px;
      padding: 0 10px;
      border: 1px solid var(--line-strong);
      border-radius: 12px;
      background: rgba(255, 255, 255, 0.055);
      color: #fff;
      font-size: 12px;
      font-weight: 850;
      text-decoration: none;
    }

    .share-button svg { width: 18px; height: 18px; flex: 0 0 auto; }
    .share-button:active { transform: scale(0.98); opacity: 0.82; }
    .share-button.whatsapp { border-color: rgba(20, 241, 149, 0.32); }
    .share-button.x { border-color: rgba(255, 255, 255, 0.22); }
    .share-button.telegram { border-color: rgba(0, 209, 255, 0.32); }
    .share-button.download { border-color: rgba(153, 69, 255, 0.34); }

    @media (max-width: 520px) {
      .winner-card {
        grid-template-columns: 1fr 1fr;
        gap: 9px;
        padding: 12px;
      }
      .winner-brand {
        align-content: start;
        gap: 42px;
      }
      .winner-logo-row { gap: 7px; }
      .winner-logo { width: 46px; }
      .winner-wordmark { gap: 1px; }
      .winner-wordmark strong {
        font-size: 20px;
        line-height: 1;
      }
      .winner-wordmark span,
      .winner-kicker,
      .winner-label {
        font-size: 7px;
        letter-spacing: 0.12em;
      }
      .winner-title {
        gap: 3px;
        margin-top: 0;
      }
      .winner-title h1 {
        font-size: 30px;
        line-height: 0.88;
      }
      .winner-title p { display: none; }
      .winner-details { gap: 7px; }
      .winner-amount {
        gap: 3px;
        padding: 8px 10px;
        border-radius: 12px;
      }
      .winner-amount strong {
        font-size: 34px;
        line-height: 0.9;
      }
      .winner-grid { gap: 6px; }
      .winner-fact {
        padding: 7px 8px;
        border-radius: 10px;
      }
      .winner-fact strong {
        font-size: 10px;
        line-height: 1.05;
        overflow-wrap: normal;
        word-break: normal;
      }
      .share-actions { grid-template-columns: repeat(2, minmax(0, 1fr)); }
      .share-button { min-height: 46px; font-size: 11px; }
    }

    /* ---------- timeline ---------- */

    .timeline { display: grid; padding: 2px 2px 0; }
    .step { display: grid; grid-template-columns: 22px 1fr; gap: 12px; }
    .step-rail { display: grid; justify-items: center; grid-template-rows: 18px 1fr; }
    .step-dot { width: 10px; height: 10px; margin-top: 5px; border-radius: 50%; background: var(--line-strong); }
    .step-dot.now { background: var(--amber); box-shadow: 0 0 0 4px rgba(245, 158, 11, 0.15), 0 0 14px rgba(245, 158, 11, 0.45); }
    .step-line { width: 2px; min-height: 24px; background: rgba(148, 163, 184, 0.16); border-radius: 2px; }
    .step-body { display: grid; gap: 2px; padding-bottom: 14px; }
    .step:last-child .step-body { padding-bottom: 2px; }
    .step-title { color: #fff; font-size: 14.5px; font-weight: 750; }
    .step-state { font-size: 11.5px; font-weight: 750; letter-spacing: 0.07em; text-transform: uppercase; }

    /* ---------- trust badges ---------- */

    .badge-grid { display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 10px; }
    .badge { padding: 13px; display: grid; gap: 9px; }
    .badge h3 { font-size: 13.5px; }
    .badge p { font-size: 12px; line-height: 1.4; }

    /* ---------- bottom nav ---------- */

    .bottom-nav {
      position: fixed;
      z-index: 30;
      left: max(12px, env(safe-area-inset-left));
      right: max(12px, env(safe-area-inset-right));
      bottom: max(12px, env(safe-area-inset-bottom));
      max-width: 728px;
      height: 72px;
      margin: 0 auto;
      display: grid;
      grid-template-columns: repeat(5, minmax(0, 1fr));
      gap: 4px;
      padding: 7px;
      border-radius: 18px;
      border: 1px solid var(--line-strong);
      background: rgba(10, 15, 23, 0.94);
      backdrop-filter: blur(22px);
      box-shadow: 0 -14px 44px rgba(0, 0, 0, 0.45), 0 0 30px rgba(124, 58, 237, 0.08);
    }

    .nav-item {
      min-width: 0;
      min-height: 58px;
      display: grid;
      place-items: center;
      gap: 3px;
      border-radius: 12px;
      background: transparent;
      color: var(--soft);
      font-size: 10.5px;
      font-weight: 750;
      letter-spacing: 0.02em;
    }
    .nav-item svg { width: 22px; height: 22px; }
    .nav-item.active {
      color: var(--violet);
      background: rgba(153, 69, 255, 0.13);
      box-shadow: inset 0 0 0 1px rgba(153, 69, 255, 0.24), 0 0 16px rgba(153, 69, 255, 0.14);
    }

    .wallet-native-space { min-height: 250px; }

    @media (min-width: 640px) {
      .pool-grid.two { grid-template-columns: repeat(2, minmax(0, 1fr)); }
      h1 { font-size: 33px; }
    }

    @media (max-width: 390px) {
      .app { padding-left: 12px; padding-right: 12px; }
      .topbar { margin-left: -12px; margin-right: -12px; padding-left: 12px; padding-right: 12px; }
      .pill { display: none; }
      .pool-facts { grid-template-columns: 1fr; }
      .cta-row { grid-template-columns: 1fr; }
      .badge-grid { grid-template-columns: 1fr; }
      h1 { font-size: 26px; }
    }
  </style>
</head>
<body>
  <div class="app ${chrome ? "" : "standalone-app"}">
    ${chrome ? topbar(onchainAvailable) : ""}
    ${body}
  </div>
  ${chrome ? bottomNav(active) : ""}
</body>
</html>`;
}

function topbar(onchainAvailable: boolean) {
  const status = onchainAvailable
    ? `<div class="pill"><span class="status-dot dot-live"></span><span>Mainnet</span></div>`
    : `<div class="pill pill-sync"><span class="status-dot dot-sync"></span><span>Mainnet &middot; Syncing</span></div>`;

  return String.raw`<header class="topbar">
  <div class="brand">
    <img src="${LOGO_MINI}" alt="" aria-hidden="true" />
    <span class="brand-text">LuckyMe<small>Solana pools</small></span>
  </div>
  <div class="top-actions">
    ${status}
    <button class="ghost-button" data-route="wallet">Wallet</button>
  </div>
</header>`;
}

function bottomNav(active: StitchScreenId) {
  const items: Array<[StitchScreenId, string, string]> = [
    ["home", ICONS.home, "Home"],
    ["pools", ICONS.pools, "Pools"],
    ["activity", ICONS.activity, "Activity"],
    ["wallet", ICONS.wallet, "Wallet"],
    ["links", ICONS.links, "Links"],
  ];

  // aria-hidden: the native wrapper renders the accessible tab controls
  // directly above this bar; hiding the duplicate avoids a double nav tree.
  return String.raw`<nav class="bottom-nav" aria-hidden="true">
  ${items.map(([screen, icon, label]) => String.raw`<button class="nav-item ${active === screen ? "active" : ""}" data-route="${screen}" tabindex="-1">
    ${icon}
    <span>${label}</span>
  </button>`).join("\n  ")}
</nav>`;
}

