const TITLES: Record<StitchScreenId, string> = {
  home: "LuckyMe | Home",
  pools: "LuckyMe | Pools",
  activity: "LuckyMe | Activity",
  wallet: "LuckyMe | Wallet",
  links: "LuckyMe | Links",
  review: "LuckyMe | Review",
  syncing: "LuckyMe | Wallet Request",
  success: "LuckyMe | Status",
  unavailable: "LuckyMe | On-chain Syncing",
  welcome: "LuckyMe | Welcome",
  winner: "LuckyMe | Winner Card",
};

const BODIES: Record<StitchScreenId, () => string> = {
  home: homeBody,
  pools: poolsBody,
  activity: activityBody,
  wallet: walletBody,
  links: linksBody,
  review: reviewBody,
  syncing: syncingBody,
  success: successBody,
  unavailable: unavailableBody,
  welcome: homeBody,
  winner: () => winnerBody(),
};

const DEFAULT_TAB: Record<StitchScreenId, StitchScreenId> = {
  home: "home",
  pools: "pools",
  activity: "activity",
  wallet: "wallet",
  links: "links",
  review: "pools",
  syncing: "pools",
  success: "activity",
  unavailable: "home",
  welcome: "home",
  winner: "activity",
};

/** Bottom tab that should be highlighted for a given screen. */
export function stitchDefaultTab(screen: StitchScreenId): StitchScreenId {
  return DEFAULT_TAB[screen];
}

/** Render a screen with header status + active tab matching real app state. */
export function renderStitchScreen(
  screen: StitchScreenId,
  options: StitchRenderOptions = {},
): string {
  const onchainAvailable = options.onchainAvailable ?? screen !== "unavailable";
  const active = options.activeTab ?? DEFAULT_TAB[screen];
  const body = screen === "winner" ? winnerBody(options.winner) : BODIES[screen]();
  return page(TITLES[screen], active, body, onchainAvailable, screen !== "winner");
}

/** Static default renders (kept for screen-id validation and previews). */
export const STITCH_SCREENS: Record<StitchScreenId, string> = {
  home: renderStitchScreen("home"),
  pools: renderStitchScreen("pools"),
  activity: renderStitchScreen("activity"),
  wallet: renderStitchScreen("wallet"),
  links: renderStitchScreen("links"),
  review: renderStitchScreen("review"),
  syncing: renderStitchScreen("syncing"),
  success: renderStitchScreen("success"),
  unavailable: renderStitchScreen("unavailable"),
  welcome: renderStitchScreen("welcome"),
  winner: renderStitchScreen("winner"),
};
